mapper.select:
SELECT , r.name AS room_name, r.type AS room_type, su1.real_name AS operator_name, su2.real_name AS closer_name FROM t_order o LEFT JOIN t_room r ON o.room_id = r.id AND r.deleted = 0 LEFT JOIN t_sys_user su1 ON o.operator_id = su1.id AND su1.deleted = 0 LEFT JOIN t_sys_user su2 ON o.closer_id = su2.id AND su2.deleted = 0 WHERE o.deleted = 0
AND o.start_time >= #{startDate}
AND o.start_time <= #{endDate}
AND o.room_id = #{roomId}
AND o.status = #{status}
ORDER BY o.create_time DESC
